/**
 * Adds ABSPATH guard to the auto-generated blocks-manifest.php.
 *
 * WordPress.org requires all PHP files that could execute code when accessed
 * directly to include an ABSPATH guard. The blocks-manifest.php file is
 * auto-generated by @wordpress/scripts and does not include this guard,
 * so this postbuild script adds it.
 */

const fs = require( 'fs' );
const path = require( 'path' );

const manifestPath = path.join(
	__dirname,
	'..',
	'assets',
	'build',
	'blocks-manifest.php'
);

if ( ! fs.existsSync( manifestPath ) ) {
	console.log( 'blocks-manifest.php not found, skipping.' );
	process.exit( 0 );
}

let content = fs.readFileSync( manifestPath, 'utf8' );

if ( content.includes( "defined( 'ABSPATH' )" ) ) {
	console.log( 'ABSPATH guard already present in blocks-manifest.php' );
	process.exit( 0 );
}

content = content.replace(
	'<?php\n',
	"<?php\nif ( ! defined( 'ABSPATH' ) ) exit; // Exit if accessed directly.\n"
);

fs.writeFileSync( manifestPath, content );
console.log( 'Added ABSPATH guard to blocks-manifest.php' );
